// Keine Items = Sync überspringen (z. B. reiner Auto-Backup-Push von n8n)
const input = $input.first().json;
const body = input.body || {};
const hc = body.head_commit;
const commits = body.commits || [];

function isBackupMessage(m) {
  return typeof m === 'string' && m.includes('Auto-Backup');
}

if (hc && isBackupMessage(hc.message)) {
  return [];
}

if (commits.length > 0 && commits.every((c) => isBackupMessage(c.message))) {
  return [];
}

return [{ json: input }];

// Extrahiere geänderte Dateien aus GitHub Webhook
const body = $json.body || {};
const commits = body.commits || [];
const changedFiles = [];
const seen = new Set();

function considerFile(file) {
  if (!file.endsWith('.json')) return;
  const base = file.split('/').pop();
  const isConfigFile = ['package.json', 'tsconfig.json', 'package-lock.json'].includes(base);
  if (isConfigFile) return;
  if (!seen.has(file)) {
    seen.add(file);
    changedFiles.push(file);
  }
}

for (const commit of commits) {
  const added = commit.added || [];
  const modified = commit.modified || [];
  for (const file of [...added, ...modified]) {
    considerFile(file);
  }
}

// Fallback: GitHub liefert bei großen Pushes oft eine leere commits-Liste
if (changedFiles.length === 0 && body.head_commit) {
  const hc = body.head_commit;
  for (const file of [...(hc.added || []), ...(hc.modified || [])]) {
    considerFile(file);
  }
}

return changedFiles.map(file => ({ filePath: file }));

const githubFile = $json;

if (githubFile.error || !githubFile.content) {
  return { error: 'Datei konnte nicht geladen werden' };
}

try {
  // Hostinger-sicheres Decoding (atob statt Buffer)
  const b64content = githubFile.content.replace(/\s/g, '');
  const content = decodeURIComponent(escape(atob(b64content)));
  const workflow = JSON.parse(content);

  // Archivierte Workflows ignorieren
  if (workflow.isArchived === true) {
    return { error: 'Archivierter Workflow wird übersprungen' };
  }

  const workflowId = workflow.id || '';
  const fileName = (githubFile.path || githubFile.name || '').split('/').pop().replace(/\.json$/, '') || 'Unnamed Workflow';
  const finalWorkflowName = workflow.name || fileName;

  // DATEN-SÄUBERUNG: Nur erlaubte Felder für die n8n-API behalten
  const workflowData = {
    name: finalWorkflowName,
    nodes: workflow.nodes || [],
    connections: workflow.connections || {},
    settings: workflow.settings || {},
    meta: workflow.meta || {}
  };

  return {
    workflowId: workflowId,
    workflowName: finalWorkflowName,
    workflowData: workflowData,
    filePath: githubFile.path || githubFile.name
  };
} catch (e) {
  return { error: 'Fehler beim Parsen: ' + e.message };
}

// Pro Item: Parse-Daten über $('...').item statt $node (korrekt bei mehreren Dateien)
const response = $json;
let parseWorkflowData;
try {
  parseWorkflowData = $('Parse Workflow').item.json;
} catch (e) {
  return { exists: false, error: 'Parse Workflow item fehlt: ' + e.message };
}

function is404(r) {
  if (r.statusCode === 404) return true;
  const err = r.error;
  const s = err ? (typeof err === 'string' ? err : JSON.stringify(err)) : '';
  if (s.includes('404')) return true;
  if (err && err.message && String(err.message).includes('404')) return true;
  return false;
}

if (response.error) {
  if (is404(response)) {
    return {
      exists: false,
      workflowId: parseWorkflowData.workflowId,
      workflowName: parseWorkflowData.workflowName,
      workflowData: parseWorkflowData.workflowData,
      filePath: parseWorkflowData.filePath
    };
  }
  return {
    exists: false,
    error: response.error.message || response.error,
    workflowId: parseWorkflowData.workflowId,
    workflowName: parseWorkflowData.workflowName,
    workflowData: parseWorkflowData.workflowData,
    filePath: parseWorkflowData.filePath
  };
}

if (response.statusCode === 200 || (response.id && response.name)) {
  return {
    exists: true,
    workflowId: parseWorkflowData.workflowId,
    workflowName: parseWorkflowData.workflowName,
    workflowData: parseWorkflowData.workflowData,
    filePath: parseWorkflowData.filePath
  };
}

return {
  exists: false,
  workflowId: parseWorkflowData.workflowId,
  workflowName: parseWorkflowData.workflowName,
  workflowData: parseWorkflowData.workflowData,
  filePath: parseWorkflowData.filePath
};

// Vorbereite workflowData für Update (item-sicher)
const analysiereData = $json;
let parseData;
try {
  parseData = $('Parse Workflow').item.json;
} catch (e) {
  throw new Error('Parse Workflow item fehlt: ' + e.message);
}
const workflowData = parseData.workflowData || {};

const finalWorkflowData = {
  name: parseData.workflowName || workflowData.name || 'Unnamed Workflow',
  nodes: workflowData.nodes || [],
  connections: workflowData.connections || {},
  settings: workflowData.settings || {}
};

return {
  workflowId: analysiereData.workflowId,
  workflowData: finalWorkflowData
};

// Vorbereite workflowData für Erstellen (item-sicher)
let parseData;
try {
  parseData = $('Parse Workflow').item.json;
} catch (e) {
  throw new Error('Parse Workflow item fehlt: ' + e.message);
}
const workflowData = parseData.workflowData || {};

const finalWorkflowData = {
  name: parseData.workflowName || workflowData.name || 'Unnamed Workflow',
  nodes: workflowData.nodes || [],
  connections: workflowData.connections || {},
  active: workflowData.active === true,
  settings: workflowData.settings || {}
};

return {
  ...parseData,
  workflowData: finalWorkflowData
};

const response = $json;
let parseData;
try {
  parseData = $('Parse Workflow').item.json;
} catch (e) {
  parseData = { workflowName: 'Unbekannt', workflowId: '' };
}

let action = 'create';
try {
  const w = $('Workflow existiert?').item.json;
  if (w && w.exists === true) action = 'update';
} catch (e) {
  action = 'create';
}

if (response.error) {
  return {
    success: false,
    error: response.error.message || response.error,
    workflowName: parseData.workflowName || 'Unbekannt',
    workflowId: parseData.workflowId || '',
    action: action
  };
}

if (response.statusCode && response.statusCode >= 400) {
  return {
    success: false,
    error: `HTTP ${response.statusCode}: ${JSON.stringify(response.body || response)}`,
    workflowName: parseData.workflowName || 'Unbekannt',
    workflowId: parseData.workflowId || '',
    action: action
  };
}

return {
  success: true,
  workflowName: response.name || parseData.workflowName || 'Unbekannt',
  workflowId: response.id || parseData.workflowId || '',
  action: action
};

// Überspringe Workflow bei Fehler
const data = $json;
return data;
